#else
#define I2C_CONTROL_INFO "I2C: "TO_STR(I2C_CONTROLLER_INST_0_NAME)", base address: "TO_STR(I2C_CONTROLLER_INST_0_BASE_ADDR)", fifo depth: "TO_STR(I2C_CONTROLLER_INST_0_FIFO_DEPTH)"\n"
#endif
#ifndef I2C_TARGET_INST_0_BASE_ADDR
#define I2C_TARGET_INFO "     Can't find I2C target device!\n"
#else
#define I2C_TARGET_INFO "     "TO_STR(I2C_TARGET_INST_0_NAME)", base address: "TO_STR(I2C_TARGET_INST_0_BASE_ADDR)"\n"
#endif
#endif

