#else
#define SPI_ADDR1 ""
#endif
#if OCTAL_SPI_CONTROLLER_INST_0_OCTAL_SPI_CONTROLLER_AXI4C_MAP
#define SPI_ADDR2 TO_STR(OCTAL_SPI_CONTROLLER_INST_0_OCTAL_SPI_CONTROLLER_AXI4C_MAP_BASE_ADDR)"  "
#else
#define SPI_ADDR2 ""
#endif
#if OCTAL_SPI_CONTROLLER_INST_0_OCTAL_SPI_CONTROLLER_APB_MAP
#define SPI_ADDR3 TO_STR(OCTAL_SPI_CONTROLLER_INST_0_OCTAL_SPI_CONTROLLER_APB_MAP_BASE_ADDR)
#else
#define SPI_ADDR3 ""
#endif
#else
#define SPI_ADDR1 TO_STR(OCTAL_SPI_CONTROLLER_INST_0_BASE_ADDR)
#define SPI_ADDR2 ""
#define SPI_ADDR3 ""
